mapper.select:
select  id, user_id, name, measure_type, value1, value2,
        happen_time, create_time, update_time
from kh_user_measure_track
where user_id = #{userId,jdbcType=BIGINT}
and happen_time >= #{startDate,jdbcType=TIMESTAMP}
and happen_time <= #{endDate,jdbcType=TIMESTAMP}
order by happen_time
